new:
private _buildKpis(items: any[]): any[] {
    const total = items.length;
    const finalized = items.filter((x) => this._isFinalized(x)).length;
    const inProduction = items.filter((x) => {
        return this._norm(x.position) === 'production' &&
            !this._isFinalized(x);
    }).length;

    const productionAffected = items.filter((x) => {
        return this._norm(x.position) === 'production' &&
            (
                this._norm(x.etatR).includes('affect') ||
                this._norm(x.etatG).includes('affect') ||
                this._norm(x.etatCqi).includes('affect') ||
                this._norm(x.etatCqc).includes('affect')
            );
    }).length;

    const late = this._countLate(items);
    const totalPages = items.reduce((sum, item) => sum + Number(item.page || 0), 0);
    const avgPages = this._avg(items.map((x) => Number(x.page || 0)));
    const pagesToday = this._pagesDeliveredToday(items);
    const returnCq = items.filter((x) => this._hasRetourCq(x)).length;

    return [
        {
            title : 'Total dossiers',
            value : total,
            delta : 'Tous les dossiers du périmètre filtré',
            scope : 'Calculé sur l\'ensemble des dossiers disponibles dans l\'API.',
            trend : 'neutral'
        },
        {
            title : 'En production',
            value : inProduction,
            delta : 'Position Production, non finalisés',
            scope : 'Dossiers actifs en production dans le périmètre filtré.',
            trend : 'neutral'
        },
        {
            title : 'Livrés / validés',
            value : finalized,
            delta : 'Statut livré ou validé',
            scope : 'Calculé sur tous les dossiers du périmètre filtré.',
            trend : 'up'
        },
        {
            title : 'Retours CQ',
            value : returnCq,
            delta : 'Dossiers avec retour CQ',
            scope : 'Calculé sur tous les dossiers du périmètre filtré.',
            trend : returnCq > 0 ? 'down' : 'up'
        },
        {
            title : 'Retards',
            value : late,
            delta : 'Date prévue dépassée, hors Client',
            scope : 'Calculé sur tous les dossiers non finalisés du périmètre filtré.',
            trend : late > 0 ? 'down' : 'up'
        },
        {
            title : 'Charge globale (pages)',
            value : totalPages,
            delta : 'Somme des pages dossier',
            scope : 'Total des pages sur tous les dossiers du périmètre filtré.',
            trend : 'neutral'
        },
        {
            title : 'Moyenne pages / dossier',
            value : avgPages,
            delta : 'Moyenne des pages par dossier',
            scope : 'Calculée sur tous les dossiers disponibles dans l\'API (périmètre filtré), tous statuts confondus.',
            trend : 'neutral'
        },
        {
            title : 'Affectés production',
            value : productionAffected,
            delta : 'Production + état affecté/en cours',
            scope : 'Sous-ensemble des dossiers en position Production.',
            trend : 'up'
        },
        {
            title : 'Pages livrées aujourd’hui',
            value : pagesToday,
            delta : 'Selon dateLivraison du jour',
            scope : 'Pages des dossiers finalisés livrés aujourd\'hui.',
            trend : 'neutral'
        }
    ];
}

private _buildPerformanceGauge(items: any[]): void
{
    const total = items.length;
    const finalized = items.filter((x) => this._isFinalized(x)).length;
    const value = total > 0 ? Math.round((finalized / total) * 100) : 0;

    let status = 'Faible';

    if (value >= 75)
    {
        status = 'Bon';
    }
    else if (value >= 50)
    {
        status = 'Modéré';
    }

    this.performanceGauge = {
        title   : 'Jauge performance globale',
        value,
        subtitle: 'Taux de dossiers livrés / validés sur le total du périmètre filtré (API .NET).',
        status
    };
}

private _countLate(items: any[]): number
{
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    return items.filter((item) => {
        const due = this._parseTriwebDate(item.dateLivraisonPrevueIso, item.annee) ||
            this._parseTriwebDate(item.dateLivraisonPrevue, item.annee);

        if (!due || this._isFinalized(item))
        {
            return false;
        }

        if (this._norm(item.position) === 'client')
        {
            return false;
        }

        due.setHours(0, 0, 0, 0);

        return due < today;
    }).length;
}

private _avg(values: number[]): number
{
    const clean = values.filter((x) => !isNaN(x));

    if (!clean.length)
    {
        return 0;
    }

    return this._round(clean.reduce((sum, value) => sum + value, 0) / clean.length);
}

