private _buildSummaryCards(items: any[]): any[] {
    const todayKey = this._dateKey(new Date());

    const todayItems = items.filter((item) => {
        return item.dateLivraisonPrevueIso === todayKey &&
            !this._isFinalized(item) &&
            this._norm(item.position) !== 'client';
    });

    const todayDelivered = items.filter((item) => {
        return item.dateLivraisonIso === todayKey && this._isFinalized(item);
    });

    const todayInProgress = items.filter((item) => {
        if (this._isFinalized(item) || this._norm(item.position) === 'client')
        {
            return false;
        }

        const isActive =
            this._norm(item.etatR).includes('cours') ||
            this._norm(item.etatG).includes('cours') ||
            this._norm(item.etatR).includes('affect') ||
            this._norm(item.etatG).includes('affect');

        return isActive && (
            item.dateLivraisonPrevueIso === todayKey ||
            item.dateLivraisonIso === todayKey
        );
    });

    const next7Days = items.filter((item) => {
        const due = this._parseTriwebDate(item.dateLivraisonPrevueIso, item.annee);

        if (!due || this._isFinalized(item))
        {
            return false;
        }

        if (this._norm(item.position) === 'client')
        {
            return false;
        }

        const today = new Date();
        today.setHours(0, 0, 0, 0);

        const maxDate = new Date(today);
        maxDate.setDate(maxDate.getDate() + 7);

        return due >= today && due <= maxDate;
    });

    const late = this._buildLateItems(items);

    const productionItems = items.filter((item) => {
        return this._norm(item.position) === 'production' &&
            !this._isFinalized(item);
    });

    const retours = items.filter((item) => {
        return this._hasRetourCq(item) &&
            this._norm(item.position) !== 'client';
    });

    const avgPagesToday = this._avg(todayItems.map((x) => Number(x.page || 0)));
    const avgPagesNext7 = this._avg(next7Days.map((x) => Number(x.page || 0)));
    const avgPagesFiltered = this._avg(items.map((x) => Number(x.page || 0)));
    const avgPagesTodayDelivered = this._avg(todayDelivered.map((x) => Number(x.page || 0)));

    return [
        {
            title : 'Planifiés aujourd\'hui',
            value : todayItems.length,
            detail: `${avgPagesToday} pages moy. / dossier`,
            scope : 'Moyenne calculée sur les dossiers planifiés pour aujourd\'hui (non finalisés).',
            trend : todayItems.length > 0 ? 'down' : 'up'
        },
        {
            title : 'En cours aujourd\'hui',
            value : todayInProgress.length,
            detail: 'Traitement actif du jour',
            scope : 'Dossiers en cours de traitement avec activité aujourd\'hui.',
            trend : 'neutral'
        },
        {
            title : 'Livrés aujourd\'hui',
            value : todayDelivered.length,
            detail: `${avgPagesTodayDelivered} pages moy. / dossier`,
            scope : 'Moyenne pages / dossier livré, calculée sur les dossiers livrés aujourd\'hui.',
            trend : 'up'
        },
        {
            title : 'Échéances 7 jours',
            value : next7Days.length,
            detail: `${avgPagesNext7} pages moy. / dossier`,
            scope : 'Moyenne pages / dossier sur les échéances des 7 prochains jours.',
            trend : next7Days.length > 0 ? 'neutral' : 'up'
        },
        {
            title : 'Retards internes',
            value : late.length,
            detail: 'Hors position Client',
            scope : 'Dossiers en retard sur la date prévue, périmètre planification filtré.',
            trend : late.length > 0 ? 'down' : 'up'
        },
        {
            title : 'En production',
            value : productionItems.length,
            detail: 'Dossiers non finalisés',
            scope : 'Dossiers actifs en production dans le périmètre filtré.',
            trend : 'neutral'
        },
        {
            title : 'Moyenne pages / dossier',
            value : avgPagesFiltered,
            detail: 'Périmètre filtré planification',
            scope : 'Moyenne des pages par dossier sur le périmètre filtré (tous statuts).',
            trend : 'neutral'
        },
        {
            title : 'Retours CQ',
            value : retours.length,
            detail: 'Hors position Client',
            scope : 'Retours CQ dans le périmètre planification filtré.',
            trend : retours.length > 0 ? 'down' : 'up'
        }
    ];
}

private _buildPlanningGauge(items: any[]): void
{
    const todayKey = this._dateKey(new Date());

    const todayPlanned = items.filter((item) => {
        return item.dateLivraisonPrevueIso === todayKey &&
            !this._isFinalized(item) &&
            this._norm(item.position) !== 'client';
    });

    const lateIds = new Set(this._buildLateItems(items).map((item) => item.id));
    const withoutLate = todayPlanned.filter((item) => !lateIds.has(item.id));
    const value = todayPlanned.length
        ? Math.round((withoutLate.length / todayPlanned.length) * 100)
        : 100;

    let status = 'Surcharge';

    if (value >= 75)
    {
        status = 'Équilibré';
    }
    else if (value >= 50)
    {
        status = 'Sous-charge';
    }

    this.planningGauge = {
        title   : 'Jauge satisfaction planning',
        value,
        subtitle: 'Dossiers planifiés aujourd\'hui sans retard / total planifiés aujourd\'hui.',
        status
    };
}

