private _getTodayPlanned(items: any[]): any[] {
    const todayKey = this._dateKey(new Date());

    return items.filter((item) => {
        return item.dateLivraisonPrevueIso === todayKey &&
            !this._isFinalized(item) &&
            this._norm(item.position) !== 'client';
    });
}

private _getTodayDelivered(items: any[]): any[] {
    const todayKey = this._dateKey(new Date());

    return items.filter((item) => {
        return item.dateLivraisonIso === todayKey && this._isFinalized(item);
    });
}

private _getTodayInProgress(items: any[]): any[] {
    const todayKey = this._dateKey(new Date());

    return items.filter((item) => {
        if (this._isFinalized(item) || this._norm(item.position) === 'client')
        {
            return false;
        }

        const isActive =
            this._norm(item.etatR).includes('cours') ||
            this._norm(item.etatG).includes('cours') ||
            this._norm(item.etatR).includes('affect') ||
            this._norm(item.etatG).includes('affect');

        return isActive && (
            item.dateLivraisonPrevueIso === todayKey ||
            item.dateLivraisonIso === todayKey
        );
    });
}

private _getTodayOperational(items: any[]): any[] {
    const map = new Map<string, any>();

    [
        ...this._getTodayPlanned(items),
        ...this._getTodayInProgress(items),
        ...this._getTodayDelivered(items)
    ].forEach((item) => {
        if (item.id)
        {
            map.set(String(item.id), item);
        }
    });

    return Array.from(map.values());
}

private _isTeamRAffected(item: any): boolean
{
    return this._roleHasWork(item.redacteur, item.etatR, item.planR);
}

private _isTeamGAffected(item: any): boolean
{
    return this._roleHasWork(item.graphiste, item.etatG, item.planG);
}

private _buildTeamRGPieToday(items: any[]): any[] {
    const operational = this._getTodayOperational(items);

    let teamR = 0;
    let teamG = 0;
    let nonAffecte = 0;

    operational.forEach((item) => {
        const hasR = this._isTeamRAffected(item);
        const hasG = this._isTeamGAffected(item);

        if (hasR)
        {
            teamR += 1;
        }

        if (hasG)
        {
            teamG += 1;
        }

        if (!hasR && !hasG)
        {
            nonAffecte += 1;
        }
    });

    return [
        { equipe: 'TeamR', value: teamR, pages: this._sumPages(operational.filter((i) => this._isTeamRAffected(i))) },
        { equipe: 'TeamG', value: teamG, pages: this._sumPages(operational.filter((i) => this._isTeamGAffected(i))) },
        { equipe: 'Non affectés', value: nonAffecte, pages: this._sumPages(operational.filter((i) => !this._isTeamRAffected(i) && !this._isTeamGAffected(i))) }
    ].filter((x) => x.value > 0);
}

private _buildTeamRGChargeToday(items: any[]): any[] {
    const operational = this._getTodayOperational(items);

    const teamRItems = operational.filter((item) => this._isTeamRAffected(item));
    const teamGItems = operational.filter((item) => this._isTeamGAffected(item));

    return [
        {
            equipe  : 'TeamR',
            pages   : this._sumPages(teamRItems),
            dossiers: teamRItems.length
        },
        {
            equipe  : 'TeamG',
            pages   : this._sumPages(teamGItems),
            dossiers: teamGItems.length
        }
    ];
}

private _buildTeamRGInProgressToday(items: any[]): any[] {
    const inProgress = this._getTodayInProgress(items);

    const teamRItems = inProgress.filter((item) => this._isTeamRAffected(item));
    const teamGItems = inProgress.filter((item) => this._isTeamGAffected(item));

    return [
        {
            equipe  : 'TeamR en cours',
            dossiers: teamRItems.length,
            pages   : this._sumPages(teamRItems)
        },
        {
            equipe  : 'TeamG en cours',
            dossiers: teamGItems.length,
            pages   : this._sumPages(teamGItems)
        }
    ];
}

private _sumPages(items: any[]): number
{
    return items.reduce((sum, item) => sum + Number(item.page || 0), 0);
}

